import source


def test_source_module_imports():
    assert source is not None
def test_bitcount_multiple_bits():
    """Bug: XOR (n ^= n - 1) instead of AND (n &= n - 1) causes infinite loop for inputs with multiple 1-bits."""
    import signal
    class TimeoutError(Exception):
        pass
    def handler(signum, frame):
        raise TimeoutError("bitcount timed out (likely infinite loop from XOR bug)")
    signal.signal(signal.SIGALRM, handler)
    signal.alarm(2)  # 2-second timeout
    try:
        result = source.bitcount(127)
        signal.alarm(0)
        assert result == 7
    except TimeoutError:
        assert False, "Infinite loop detected - bug confirmed"
